/**
 * @munesoft/objx — has / del
 * Deep property existence check and deletion.
 */
/**
 * Check whether a deeply nested path exists on an object.
 *
 * @example
 * has({ a: { b: 1 } }, "a.b")  // true
 * has({ a: { b: 1 } }, "a.c")  // false
 * has({ a: null }, "a.b")       // false
 */
export declare function has(obj: unknown, path: string): boolean;
/**
 * Delete a deeply nested property. Returns true if the property was deleted.
 * Does not throw if the path does not exist.
 *
 * @example
 * const obj = { a: { b: 1, c: 2 } };
 * del(obj, "a.b"); // true — obj is now { a: { c: 2 } }
 */
export declare function del(obj: unknown, path: string): boolean;
/**
 * Apply deep default values: only sets keys that are undefined in target.
 *
 * @example
 * defaults({ a: 1 }, { a: 99, b: 2 }) // { a: 1, b: 2 }
 */
export declare function defaults<T extends object>(target: T, source: Partial<T>): T;
